<script>
import { getBankList, createCorp, checkPerson, checkCorp } from '@/api/dealerReInfo'
import areaData from '@/common/area.json'
import ResultCpn from '@/view/base/setting/dealer/cpn/result.vue'
import { MaxRules, requiredRules } from '@/view/base/setting/dealer/tools'
import loadingBtn from '@/components/loading-btn'
export default {
  components: {
    loadingBtn
  },
  props: ['activeName', 'info'],
  data() {
    return {
      // 初始打開tab
      // 填寫的類型
      member_type: '',
      allShow: true,
      // 全部地區
      AllArea: areaData,
      processed: '',
      currentStatus: {
        resultStatus: '',
        time: '',
        info: '',
        title: ''
      },
      // 全部銀行
      AllBank: [],
      // 選中地區
      area: '',
      form: {
        name: '', //企業名稱
        area: '', // 省份編碼地區編碼
        business_scope: '', //經營範圍
        social_credit_code: '', // 統一社會信用碼
        social_credit_code_expires: '', //統一社會信用證有效期(1121),
        telphone: '', //企業電話
        zip_code: '', //郵編
        email: '', // 企業郵箱
        legal_person: '', //法人姓名
        legal_cert_id: '', //法人身份證號碼
        legal_cert_id_expires: '', // 法人身份證有效期(20220112)
        legal_mp: '', // 法人手機號
        address: '', //企業地址
        attach_file: '', //上傳附件
        bank_code: '', // 銀行代碼
        bank_name: '',
        bank_acct_type: '1', //銀行賬戶類型：1-對公；2-對私
        card_no: '', //銀行卡號
        card_name: '', //銀行卡對應的戶名，若銀行賬戶類型是對公，必須與企業名稱一致,
        submit_review: '', //是否提交審核(Y/N)
        isUploadFile: true, // 加這個走formdata格式
        attach_file_name: '',
        confirm_letter_file: '',
        confirm_letter_file_name: ''
      },
      rules: {
        name: requiredRules('企業名稱'),
        social_credit_code: [requiredRules('營業執照號'), MaxRules(18)],
        social_credit_code_expires: {
          required: true,
          message: '請選擇商戶有效期',
          trigger: 'blur'
        },
        area: { type: 'array', required: true, message: '請選擇省市', trigger: 'change' },
        address: [requiredRules('企業地址'), MaxRules(60)],
        business_scope: requiredRules('經營範圍'),
        legal_person: [requiredRules('法人姓名'), MaxRules(20)],
        legal_cert_id: [requiredRules('法人身份證號'), MaxRules(18)],
        legal_cert_id_expires: { required: true, message: '請選擇法人證件有效期', trigger: 'blur' },
        legal_mp: [requiredRules('法人手機號'), MaxRules(11)],
        bank_acct_type: [requiredRules('結算銀行賬戶類型', 'change')],
        bank_name: { required: true, message: '請輸入並選擇', trigger: 'blur' },
        card_name: [requiredRules('結算銀行卡開戶名'), MaxRules(20)],
        card_no: [requiredRules('結算銀行卡卡號'), MaxRules(40)],
        attach_file: { required: true, message: '請上傳', trigger: 'change' },
        confirm_letter_file: { required: true, message: '請上傳', trigger: 'change' }
      },
      personForm: {
        user_name: '', //用戶姓名
        tel_no: '', // 用戶手機號碼
        cert_id: '', // 用戶身份證號碼
        bank_card_name: '', //開戶人姓名
        bank_tel_no: '', //銀行預留手機號
        bank_card_id: '', //銀行賬號
        bank_cert_id: '' // 開戶人證件號碼
      },
      personRules: {
        user_name: [requiredRules('用戶姓名'), MaxRules(20)],
        tel_no: [requiredRules('用戶手機號碼'), MaxRules(11)],
        cert_id: [requiredRules('用戶身份證號碼'), MaxRules(18)],
        bank_card_name: [requiredRules('開戶人姓名'), MaxRules(20)],
        bank_tel_no: [requiredRules('銀行預留手機號'), MaxRules(11)],
        bank_card_id: [requiredRules('銀行賬號'), MaxRules(40)],
        bank_cert_id: [requiredRules('開戶人證件號碼'), MaxRules(18)]
      },
      isShow_corp: false,
      isShow_person: false,
      type: '',
      id: ''
    }
  },
  mounted() {
    if (this.activeName == 'corp') {
      this.form = this.info
      this.form.area = [this.form.prov_code, this.form.area_code]
    } else {
      this.personForm = this.info
    }
  },
  methods: {
    submitHandle(formName, isSubmit) {
      this.$refs[formName].validate(async (valid) => {
        if (valid) {
          if (formName == 'ruleForm') {
            this.$confirm(
              '未避免影響提現，請確認結算卡持卡人姓名與法人一致，信息更改需審核，請確認是否提交。',
              '提示消息',
              {
                confirmButtonText: '確定',
                type: 'warning',
                showCancelButton: false
              }
            ).then(() => {
              this.submitForm(formName, isSubmit)
            })
          } else {
            this.$confirm('結算賬戶信息更改需提交審核，請確認是否提交', '提示消息', {
              confirmButtonText: '確定',
              type: 'warning',
              showCancelButton: false
            }).then(() => {
              this.submitFormPerson(formName, isSubmit)
            })
          }
        } else {
          this.$message.error('請完善您的信息')
        }
      })
    },
    async submitForm(formName, isSubmit) {
      this.form.submit_review = isSubmit
      this.form.isUploadFile = true
      console.log(this.form)

      const result = await this.$api.adapay.accountUpdate(this.form)
      if (result.data.data.status) {
        this.$message.success('提交成功')
        this.$emit('back')
      } else {
        this.$message.error('失敗')
      }
    },
    async submitFormPerson(formName, isSubmit) {
      this.personForm.submit_review = isSubmit
      const result = await this.$api.adapay.accountUpdatePerson(this.personForm)
      if (result.data.data.status) {
        this.$message.success('提交成功')
        this.$emit('back')
      } else {
        this.$message.error('失敗')
      }
    },
    handleAvatarSuccess(file) {
      console.log(file)
    },
    handleUpload: function (file) {
      this.form.attach_file_name = file.file.name
      this.form.attach_file = file.file
    },
    beforeAvatarUpload(file) {
      console.log(file)
      const isZip = file.type === 'application/zip' || file.type === 'application/x-zip-compressed'
      const isLt2M = file.size / 1024 / 1024 < 8
      if (!isZip) {
        this.$message.error('文件類型應為Zip')
      }
      if (!isLt2M) {
        this.$message.error('上傳文件不能超過 8MB!')
      }
      return isZip && isLt2M
    },
    goback() {
      this.$router.back(-1)
    },
    async processedHandle() {
      if (this.member_type == 'corp') {
        const result = await this.$api.adapay.accountQueryCorp()
        this.processed = '未填'
        this.form = result.data.data
        this.form.area = [this.form.prov_code, this.form.area_code]
        console.log(result)
      } else {
        const result = await this.$api.adapay.accountQueryCorp()
        this.processed = '未填'
        this.personForm = result.data.data
        this.activeName = 'person'
        console.log(result)
      }
    },

    // type 判斷結果 （獲取保存的結果）
    async getResult(id, type, member_type) {
      this.id = id

      if (id && member_type == 'corp') {
        this.activeName = member_type
        this.isShow_person = true
        const result = await checkCorp(id)
        this.form = result.data.data

        const {
          area_code,
          prov_code,
          social_credit_code_expires,
          legal_cert_id_expires,
          attach_file_name,
          confirm_letter_file_name,
          bank_code,
          bank_name
        } = result.data.data
        this.form.area = [prov_code, area_code]
        this.form.attach_file_name = attach_file_name
        this.form.confirm_letter_file_name = confirm_letter_file_name

        console.log('corp---------', result)
      } else if (id && member_type == 'person') {
        this.isShow_corp = true
        this.activeName = member_type
        const result = await checkPerson(id)

        this.personForm = result.data.data
        console.log('person---------', result)
      } else {
        console.log('增加')
        this.isShow_person = true
        this.isShow_corp = true
        this.activeName = 'corp'
      }
    },
    // 結算所屬銀行
    async querySearch(queryString, cb) {
      const result = await this.$api.adapay.getBank({
        bank_name: this.form.bank_name
      })
      this.AllBank = result.data.data

      var restaurants = this.AllBank.map((item) => {
        return {
          value: item.bank_name,
          bank_code: item.bank_code,
          id: item.id
        }
      })
      var results = queryString ? restaurants.filter(this.createFilter(queryString)) : restaurants
      //調用 callback 返回建議列表的數據
      cb(results)
    },
    createFilter(queryString) {
      return (restaurant) => {
        return restaurant.value.toLowerCase().indexOf(queryString.toLowerCase()) === 0
      }
    },
    async get_bank() {
      const result = await getBankList()
      this.AllBank = result.data.data
    },
    handleSelectBank(val) {
      console.log(val)
      this.form.bank_code = val.bank_code
      this.form.bank_name = val.value
    }
  }
}
</script>

